let summ = require('./summ');
let abs = require('./abs');

let min = function(arr){

    let min = arr[0];
    
    arr.forEach(function(elem){
        if(elem<min)
            min = elem;
    })

    // console.log('Згенерований масив: '+arr);
    // console.log('Mінімальний елемент масиву: ' + min);
    // console.log('Сума всіх елементів масиву: '+summ(arr));
    // console.log('Модуль першого елемннту масиву: '+abs(arr[0]));

    return min;
}

module.exports = min;

